import sys
import re

def process_line(line):
    # Ignore anything after '|'
    line = line.split('|')[0].strip()
    match = re.search(r'(?P<name>\w+) (has|had|has) (?P<N>\d+) (apples|candies|marbles) (and|gave|gives) (buys|away) (?P<M>\d+)( more)?', line)
    if match:
        name = match.group('name')
        N = int(match.group('N'))
        M = int(match.group('M'))
        if 'buys' in line:
            return N + M
        elif 'gave' in line or 'gives' in line:
            if M <= N:
                return N - M
            else:
                return 'INVALID'
    return 'INVALID'

if __name__ == '__main__':
    input = sys.stdin.read
    data = input().strip().split('\n')
    t = int(data[0])
    results = []
    for i in range(1, t + 1):
        results.append(process_line(data[i]))
    print('\n'.join(map(str, results)))
